mapper.select:
SELECT j.job_name AS jobName, j.job_group AS jobGroup, COUNT(l.id) AS totalCount, SUM(CASE WHEN l.status = 1 THEN 1 ELSE 0 END) AS successCount, SUM(CASE WHEN l.status = 0 THEN 1 ELSE 0 END) AS failCount, AVG(l.duration) AS avgDuration FROM sparkit_job j LEFT JOIN sparkit_job_log l ON j.id = l.job_id
AND l.create_time >= #{startTime}
AND l.create_time <= #{endTime}
GROUP BY j.id, j.job_name, j.job_group ORDER BY totalCount DESC

SELECT COUNT(*) AS totalCount, SUM(CASE WHEN status = 1 THEN 1 ELSE 0 END) AS successCount, SUM(CASE WHEN status = 0 THEN 1 ELSE 0 END) AS failCount, ROUND(SUM(CASE WHEN status = 1 THEN 1 ELSE 0 END) * 100.0 / COUNT(*), 2) AS successRate FROM sparkit_job_log
AND create_time >= #{startTime}
AND create_time <= #{endTime}
